// extractToken safely extracts the authentication token from gRPC metadata
func (ai *AuthInterceptor) extractToken(ctx context.Context) (string, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return "", status.Error(codes.Unauthenticated, "missing metadata")
	}

	authHeaders := md.Get("authorization")
	if len(authHeaders) == 0 {
		return "", status.Error(codes.Unauthenticated, "missing authorization header")
	}

	// Use only the first authorization header
	authHeader := authHeaders[0]

	// Expect "Bearer <token>" format
	const bearerPrefix = "Bearer "
	if !strings.HasPrefix(authHeader, bearerPrefix) {
		return "", status.Error(codes.Unauthenticated, "invalid authorization format")
	}

	token := strings.TrimPrefix(authHeader, bearerPrefix)
	token = strings.TrimSpace(token)

	if len(token) == 0 {
		return "", status.Error(codes.Unauthenticated, "empty token")
	}

	// Enforce maximum token length to prevent abuse
	if len(token) > 1024 {
		return "", status.Error(codes.Unauthenticated, "token too long")
	}

	return token, nil
}

// validateToken validates the HMAC-based service mesh token
// Token format: serviceName.issuedAtUnix.expiresAtUnix.hmacSignature
func (ai *AuthInterceptor) validateToken(token string) (*TokenInfo, error) {
	// Check cache first
	if info, ok := ai.tokenCache.Get(token); ok {
		return info, nil
	}

	// Check if token is revoked
	tokenHash := hashToken(token)
	if ai.revokedStore.IsRevoked(tokenHash) {
		return nil, status.Error(codes.Unauthenticated, "token has been revoked")
	}

	parts := strings.SplitN(token, ".", 4)
	if len(parts) != 4 {
		return nil, status.Error(codes.Unauthenticated, "malformed token")
	}

	serviceName := parts[0]
	issuedAtStr := parts[1]
	expiresAtStr := parts[2]
	providedSignature := parts[3]

	// Validate service name (alphanumeric and hyphens only)
	if !isValidServiceName(serviceName) {
		return nil, status.Error(codes.Unauthenticated, "invalid service name in token")
	}

	// Verify HMAC signature
	message := fmt.Sprintf("%s.%s.%s", serviceName, issuedAtStr, expiresAtStr)
	expectedSignature := computeHMAC(message, serviceSecret)

	if subtle.ConstantTimeCompare([]byte(providedSignature), []byte(expectedSignature)) != 1 {
		return nil, status.Error(codes.Unauthenticated, "invalid token signature")
	}

	// Parse timestamps
	var issuedAt, expiresAt int64
	if _, err := fmt.Sscanf(issuedAtStr, "%d", &issuedAt); err != nil {
		return nil, status.Error(codes.Unauthenticated, "invalid token timestamp")
	}
	if _, err := fmt.Sscanf(expiresAtStr, "%d", &expiresAt); err != nil {
		return nil, status.Error(codes.Unauthenticated, "invalid token timestamp")
	}

	issuedTime := time.Unix(issuedAt, 0)
	expiresTime := time.Unix(expiresAt, 0)
	now := time.Now()

	// Check token is not from the future (with small clock skew allowance)
	if issuedTime.After(now.Add(30 * time.Second)) {
		return nil, status.Error(codes.Unauthenticated, "token issued in the future")
	}

	// Check token expiration
	if now.After(expiresTime) {
		return nil, status.Error(codes.Unauthenticated, "token expired")
	}

	// Check token lifetime is reasonable (max 1 hour)
	if expiresTime.Sub(issuedTime) > time.Hour {
		return nil, status.Error(codes.Unauthenticated, "token lifetime too long")
	}

	info := &TokenInfo{
		ServiceName: serviceName,
		IssuedAt:    issuedTime,
		ExpiresAt:   expiresTime,
	}

	// Cache the validated token
	ai.tokenCache.Set(token, info)

	return info, nil
}

// authorizeService checks if the calling service is allowed to access the method
func (ai *AuthInterceptor) authorizeService(serviceName string, fullMethod string) error {
	allowedMethods, ok := ai.allowedServices[serviceName]
	if !ok {
		return status.Errorf(codes.PermissionDenied, "service %q is not authorized", serviceName)
	}

	for _, method := range allowedMethods {
		if method == fullMethod {
			return nil
		}
	}

	return status.Errorf(codes.PermissionDenied, "service %q is not authorized for method %q", serviceName, fullMethod)
}

// UnaryInterceptor returns a gRPC unary server interceptor for authentication
func (ai *AuthInterceptor) UnaryInterceptor() grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		// Skip auth for health checks if desired
		if info.FullMethod == "/grpc.health.v1.Health/Check" {
			return handler(ctx, req)
		}

		token, err := ai.extractToken(ctx)
		if err != nil {
			log.Printf("AUTH FAILURE: failed to extract token for %s: %v", info.FullMethod, err)
			return nil, err
		}

		tokenInfo, err := ai.validateToken(token)
		if err != nil {
			log.Printf("AUTH FAILURE: invalid token for %s: %v", info.FullMethod, err)
			return nil, err
		}

		// Authorize the service for this specific method
		if err := ai.authorizeService(tokenInfo.ServiceName, info.FullMethod); err != nil {
			log.Printf("AUTHZ FAILURE: service=%s method=%s: %v", tokenInfo.ServiceName, info.FullMethod, err)
			return nil, err
		}

		// Add service identity to context for downstream use
		ctx = context.WithValue(ctx, contextKeyServiceName, tokenInfo.ServiceName)
		ctx = context.WithValue(ctx, contextKeyTokenInfo, tokenInfo)

		log.Printf("AUTH SUCCESS: service=%s method=%s", tokenInfo.ServiceName, info.FullMethod)
		return handler(ctx, req)
	}
}

// StreamInterceptor returns a gRPC stream server interceptor for authentication
func (ai *AuthInterceptor) StreamInterceptor() grpc.StreamServerInterceptor {
	return func(
		srv interface{},
		ss grpc.ServerStream,
		info *grpc.StreamServerInfo,
		handler grpc.StreamHandler,
	) error {
		token, err := ai.extractToken(ss.Context())
		if err != nil {
			log.Printf("AUTH FAILURE (stream): failed to extract token for %s: %v", info.FullMethod, err)
			return err
		}

		tokenInfo, err := ai.validateToken(token)
		if err != nil {
			log.Printf("AUTH FAILURE (stream): invalid token for %s: %v", info.FullMethod, err)
			return err
		}

		if err := ai.authorizeService(tokenInfo.ServiceName, info.FullMethod); err != nil {
			log.Printf("AUTHZ FAILURE (stream): service=%s method=%s: %v", tokenInfo.ServiceName, info.FullMethod, err)
			return err
		}

		log.Printf("AUTH SUCCESS (stream): service=%s method=%s", tokenInfo.ServiceName, info.FullMethod)

		wrapped := &authenticatedServerStream{
			ServerStream: ss,
			ctx:          context.WithValue(ss.Context(), contextKeyServiceName, tokenInfo.ServiceName),
		}
		return handler(srv, wrapped)
	}
}

// authenticatedServerStream wraps a grpc.ServerStream with an enriched context
type authenticatedServerStream struct {
	grpc.ServerStream
	ctx context.Context
}

func (s *authenticatedServerStream) Context() context.Context {
	return s.ctx
}

// Context keys
type contextKey string

const (
	contextKeyServiceName contextKey = "service-name"
	contextKeyTokenInfo   contextKey = "token-info"
)

// GetServiceName extracts the authenticated service name from context
func GetServiceName(ctx context.Context) (string, bool) {
	name, ok := ctx.Value(contextKeyServiceName).(string)
	return name, ok
}

// Helper functions

func computeHMAC(message string, secret []byte) string {
	mac := hmac.New(sha256.New, secret)
	mac.Write([]byte(message))
	return hex.EncodeToString(mac.Sum(nil))
}

func hashToken(token string) string {
	h := sha256.Sum256([]byte(token))
	return hex.EncodeToString(h[:])
}

func isValidServiceName(name string) bool {
	if len(name) == 0 || len(name) > 63 {
		return false
	}
	for _, c := range name {
		if !((c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') || c == '-') {
			return false
		}
	}
	// Must not start or end with hyphen
	if name[0] == '-' || name[len(name)-1] == '-' {
		return false
	}
	return true
}

// GenerateServiceToken creates a token for service-to-service communication
// This would typically be called by the service mesh sidecar or token issuer
func GenerateServiceToken(serviceName string, ttl time.Duration) (string, error) {
	if !isValidServiceName(serviceName) {
		return "", fmt.Errorf("invalid service name: %s", serviceName)
	}
	if ttl > time.Hour {
		return "", fmt.Errorf("token TTL too long, max 1 hour")
	}
	if ttl <= 0 {
		return "", fmt.Errorf("token TTL must be positive")
	}

	now := time.Now()
	issuedAt := now.Unix()
	expiresAt := now.Add(ttl).Unix()

	message := fmt.Sprintf("%s.%d.%d", serviceName, issuedAt, expiresAt)
	signature := computeHMAC(message, serviceSecret)

	return fmt.Sprintf("%s.%d.%d.%s", serviceName, issuedAt, expiresAt, signature), nil
}

